const f = data.series[0];
const get = (n) => { const fld = f.fields.find(x => x.name === n); return fld ? fld.values.toArray ? fld.values.toArray() : fld.values : []; };
const X=get('x'), Y=get('y'), Z=get('z'), L=get('label'), K=get('kind'), C=get('collection'), T=get('type'), H=get('hit');
const COLL={'claude-memory-dir':'#4e79a7','claude-memory-root':'#a0cbe8','openclaw-memory-dir':'#59a14f','openclaw-memory-root':'#8cd17d'};
const TYPE={exact:'#e15759',semantic:'#f28e2b',topical:'#b07aa1',alias:'#76b7b2','cross-domain':'#ff9da7'};
const traces=[]; const is3d=false;
const groups={};
for(let i=0;i<X.length;i++){ const isq=K[i]==='query'; const key=isq?('query: '+T[i]):('doc: '+C[i]); (groups[key]??=[]).push(i); }
for(const [name,idx] of Object.entries(groups)){
  const isq=name.startsWith('query');
  const tr={name, mode:'markers', type:is3d?'scatter3d':'scatter',
    x:idx.map(i=>X[i]), y:idx.map(i=>Y[i]),
    text:idx.map(i=>L[i]+(isq?('<br>type='+T[i]+' hit='+H[i]):'')), hoverinfo:'text',
    marker:{ size:isq?11:5, opacity:isq?1:0.55,
      color: isq?(TYPE[T[idx[0]]]||'#000'):(COLL[C[idx[0]]]||'#bab0ac'),
      symbol: isq?idx.map(i=>String(H[i])==='false'?'circle-open':'diamond'):'circle',
      line: isq?{width:1.5,color:'#222'}:undefined } };
  if(is3d) tr.z=idx.map(i=>Z[i]);
  traces.push(tr);
}
return { data:traces, layout:{ margin:{l:0,r:0,t:10,b:0}, legend:{itemsizing:'constant'},
  scene:{xaxis:{title:'PC1'},yaxis:{title:'PC2'},zaxis:{title:'PC3'}}, xaxis:{title:'PC1',type:'linear'}, yaxis:{title:'PC2',type:'linear'} } };

